import{$ as e,A as t,B as n,V as r}from"./chunks/framework.qypF2UUz.js";import"./chunks/assets.DIDPfOhs.js";var i=JSON.parse(`{"title":"Introduction","description":"","frontmatter":{"prev":false,"next":false},"headers":[],"relativePath":"docs/quick-start.md","filePath":"docs/quick-start.md"}`),a={name:`docs/quick-start.md`};function o(t,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[r(`<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to “Introduction”">​</a></h1><p>If you&#39;ve ever wanted an easier way to manage your MiSTer FPGA game library, search for games, apply filters, and launch them quickly from any device, you&#39;re in the right place.</p><p><strong>MiSTer FPGA Smart Launcher</strong> consists of two applications:</p><ul><li><strong>Smart Scanner</strong> — a Windows application that scans your MiSTer FPGA game library and associates metadata with your games, enabling powerful search and filtering.</li><li><strong>Smart Launcher</strong> — a web application installed on your MiSTer FPGA that lets you browse generated database, search, filter, and launch your games directly on MiSTer FPGA from any device with a web browser.</li></ul><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Although this guide may look long, the setup process is much simpler than it appears.</p><p>Follow each section in order and you&#39;ll be ready in just a few minutes.</p></div><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>For convenience, <strong>Smart Scanner</strong> and <strong>Smart Launcher</strong> will always be released together using the same version number</p></div><h2 id="supported-systems" tabindex="-1">Supported Systems <a class="header-anchor" href="#supported-systems" aria-label="Permalink to “Supported Systems”">​</a></h2><p>The following systems are currently supported:</p><table tabindex="0"><thead><tr><th>System</th><th style="text-align:center;">Core (RBF)</th><th style="text-align:center;">Supported formats</th></tr></thead><tbody><tr><td>Amiga</td><td style="text-align:center;">_Computer/Minimig</td><td style="text-align:center;">.adf</td></tr><tr><td>Amstrad</td><td style="text-align:center;">_Computer/Amstrad</td><td style="text-align:center;">.dsk .e?? .cdt</td></tr><tr><td>Apple II</td><td style="text-align:center;">_Computer/Apple-II</td><td style="text-align:center;">.nib .dsk .do .po .hdv</td></tr><tr><td>Arcade</td><td style="text-align:center;">_Arcade/cores</td><td style="text-align:center;">.mra</td></tr><tr><td>Atari 2600</td><td style="text-align:center;">_Console/Atari7800</td><td style="text-align:center;">.a78 .a26 .bin</td></tr><tr><td>Atari 5200</td><td style="text-align:center;">_Console/Atari5200</td><td style="text-align:center;">.car .a52 .bin .rom</td></tr><tr><td>Atari 7800</td><td style="text-align:center;">_Console/Atari7800</td><td style="text-align:center;">.a78 .bin</td></tr><tr><td>Atari 800</td><td style="text-align:center;">_Computer/Atari800</td><td style="text-align:center;">.atr .xex .atx .xfd .car .rom .bin</td></tr><tr><td>Atari Lynx</td><td style="text-align:center;">_Console/AtariLynx</td><td style="text-align:center;">.lnx .lyx</td></tr><tr><td>ColecoVision</td><td style="text-align:center;">_Console/ColecoVision</td><td style="text-align:center;">.col .bin .rom</td></tr><tr><td>Commodore 64</td><td style="text-align:center;">_Computer/C64</td><td style="text-align:center;">.d64 .g64 .t64 .d81 .prg .crt .reu .tap</td></tr><tr><td>Commodore VIC-20</td><td style="text-align:center;">_Computer/VIC20</td><td style="text-align:center;">.d64 .g64 .prg .crt .ct? .tap .rom</td></tr><tr><td>Nintendo Game Boy</td><td style="text-align:center;">_Console/Gameboy</td><td style="text-align:center;">.gb</td></tr><tr><td>Nintendo Game Boy Advance</td><td style="text-align:center;">_Console/GBA</td><td style="text-align:center;">.gba</td></tr><tr><td>Nintendo Game Boy Color</td><td style="text-align:center;">_Console/Gameboy</td><td style="text-align:center;">.gbc</td></tr><tr><td>Sega Genesis</td><td style="text-align:center;">_Console/Genesis</td><td style="text-align:center;">.bin .gen .md</td></tr><tr><td>Sega Master System</td><td style="text-align:center;">_Console/SMS</td><td style="text-align:center;">.sms</td></tr><tr><td>Sega Mega Drive</td><td style="text-align:center;">_Console/MegaDrive</td><td style="text-align:center;">.bin .gen .md</td></tr><tr><td>MSX 1</td><td style="text-align:center;">_Computer/MSX1</td><td style="text-align:center;">.rom</td></tr><tr><td>Neo Geo</td><td style="text-align:center;">_Console/NeoGeo</td><td style="text-align:center;">.neo</td></tr><tr><td>Nintendo / Famicom</td><td style="text-align:center;">_Console/NES</td><td style="text-align:center;">.nes</td></tr><tr><td>Nintendo 64</td><td style="text-align:center;">_Console/N64</td><td style="text-align:center;">.z64 .n64</td></tr><tr><td>Sony PlayStation</td><td style="text-align:center;">_Console/PSX</td><td style="text-align:center;">.cue .bin .img .chd</td></tr><tr><td>Sega Saturn</td><td style="text-align:center;">_Console/Saturn</td><td style="text-align:center;">.cue .bin .img .chd</td></tr><tr><td>Sega Mega CD</td><td style="text-align:center;">_Console/MegaCD</td><td style="text-align:center;">.chd</td></tr><tr><td>Super Nintendo / Super Famicom</td><td style="text-align:center;">_Console/SNES</td><td style="text-align:center;">.sfc</td></tr><tr><td>ZX Spectrum</td><td style="text-align:center;">_Computer/ZX-Spectrum</td><td style="text-align:center;">.trd .img .dsk .mgt .tap .csw .tzx .z80 .sna .vhd</td></tr><tr><td>PC Engine / TurboGrafx-16</td><td style="text-align:center;">_Console/TurboGrafx16</td><td style="text-align:center;">.bin .pce</td></tr><tr><td>PC Engine CD / TurboGrafx-16 CD</td><td style="text-align:center;">_Console/TurboGrafx16</td><td style="text-align:center;">.cue .bin .img .chd</td></tr><tr><td>Vectrex</td><td style="text-align:center;">_Console/Vectrex</td><td style="text-align:center;">.vec .bin .rom</td></tr><tr><td>Sharp X68000</td><td style="text-align:center;">_Computer/X68000</td><td style="text-align:center;">.d88 .hdf .ram</td></tr></tbody></table><hr><h2 id="roms-in-zip-archive" tabindex="-1">ROMs in ZIP archives <a class="header-anchor" href="#roms-in-zip-archive" aria-label="Permalink to “ROMs in ZIP archives”">​</a></h2><p>ROMs stored inside <code>.zip</code> archives are also supported.</p><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Most MiSTer cores do <strong>not</strong> support launching ZIP files directly.</p><p>However, when using the standard MiSTer UI file browser, ZIP archives are displayed like folders. After selecting the ROM inside the archive, MiSTer automatically extracts it and passes it to the appropriate core.</p><p>Smart launcher do the same thing: When you will select a game to Play using Smart Launcher web app, the system will unpack the zip archive in a temporary folder and then will launch the rom using the required core</p></div><h2 id="smart-scanner" tabindex="-1">Smart Scanner <a class="header-anchor" href="#smart-scanner" aria-label="Permalink to “Smart Scanner”">​</a></h2><figure><img src="/assets/1.Pnzy8MA-.png" alt="Smart Scanner"></figure><p>Smart Scanner is a Windows application that scans the ROM collection installed on your MiSTer FPGA.</p><p>During the scan, it can associate metadata with your games, making them searchable by title, genre, year, publisher, and more.</p><p>Once the scan is complete, Smart Scanner generates a <strong>database</strong> folder that can be copied directly to your MiSTer FPGA.</p><p>Ok, here we go -&gt; Launch Smart Scanner and click <strong>Next</strong> to begin.</p><h3 id="smart-scanner-add-your-systems" tabindex="-1">Add Your Systems <a class="header-anchor" href="#smart-scanner-add-your-systems" aria-label="Permalink to “Add Your Systems”">​</a></h3><figure><img src="/assets/2.Dra9iXIF.png" alt="Smart Scanner"></figure><p>The first step let you decide which systems (or platforms) you want to scan.</p><p>Click <strong>Add System</strong> to add a new platform.</p><p>For each system you must specify:</p><ul><li>The folder containing the ROMs.</li><li>The corresponding ROM path on your MiSTer FPGA.</li></ul><figure><img src="/assets/3.BVxY7Nmb.png" alt="Smart Scanner"></figure><p>There are two ways to select your ROM folder.</p><h3 id="option-1-—-local-rom-collection" tabindex="-1">Option 1 — Local ROM Collection <a class="header-anchor" href="#option-1-—-local-rom-collection" aria-label="Permalink to “Option 1 — Local ROM Collection”">​</a></h3><p>If your PC contains the same ROM collection as your MiSTer FPGA, simply select the local folder.</p><h3 id="option-2-—-browse-your-mister-over-the-network" tabindex="-1">Option 2 — Browse Your MiSTer Over the Network <a class="header-anchor" href="#option-2-—-browse-your-mister-over-the-network" aria-label="Permalink to “Option 2 — Browse Your MiSTer Over the Network”">​</a></h3><p>If your MiSTer FPGA is connected to your local network, Smart Scanner can access it directly.</p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>This requires the <strong>Samba</strong> service to be enabled on your MiSTer FPGA.</p><p>You can download the script from <a href="https://github.com/MiSTer-devel/Scripts_MiSTer" target="_blank" rel="noreferrer">here</a></p></div><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Browsing directly your MiSTer FPGA folders can drastically increase the time required to scan the ROM set and database generation.</p></div><p>Run the <code>samba_on</code> script from the <strong>Scripts</strong> menu on your MiSTer.</p><p>If the script is not available, download it and copy it into your <code>Scripts</code> folder before running it.</p><p>Once Samba is enabled, your MiSTer will be accessible from Windows File Explorer.</p><p>When selecting the ROM folder, enter inside the searchbar path the IP address of your MiSTer:</p><p>For example:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>\\\\192.168.3.10</span></span></code></pre></div><p>You will then be able to browse your MiSTer folders directly from Windows.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>After configuring all your systems, click <strong>Export Profile</strong> to save your configuration.</p><p>You can import it later without repeating the setup process.</p></div><p>When you&#39;re finished, click <strong>Next</strong>.</p><h3 id="smart-scanner-apply-metadata" tabindex="-1">Apply Metadata <a class="header-anchor" href="#smart-scanner-apply-metadata" aria-label="Permalink to “Apply Metadata”">​</a></h3><figure><img src="/assets/4.DmPJszDN.png" alt="Smart Scanner"></figure><p>Smart Scanner can associate metadata with every ROM.</p><p>You have three options:</p><ul><li><p><strong>No Metadata</strong> — Skip metadata generation.</p></li><li><p><strong>PigSaint</strong> — Download and use the official PigSaint CSV metadata database.</p></li><li><p><strong>User</strong> — Use your own CSV file.</p></li></ul><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Without metadata, Smart Launcher&#39;s filtering features will not be available.</p></div><p>If you choose <strong>User</strong>, you can start from the provided CSV template.</p><p>The <code>TAGS</code> column is used to assign metadata to each ROM.</p><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Custom tags must follow the same naming convention used by the PigSaint dataset.</p></div><p>Refer to the <a href="https://github.com/PigSaint/GameDataBase" target="_blank" rel="noreferrer">PigSaint documentation</a> documentation for the complete list of supported tags and the naming convention to use.</p><h3 id="smart-scanner-generate-database" tabindex="-1">Generate Database <a class="header-anchor" href="#smart-scanner-generate-database" aria-label="Permalink to “Generate Database”">​</a></h3><figure><img src="/assets/5.BuBnBx-w.png" alt="Smart Scanner"></figure><p>After the scan completes, Smart Scanner generates a folder named <strong>database</strong>.</p><p>If you enable <strong>Override Existing Database</strong>, select the existing <code>index.db</code> file from your current database folder.</p><p>Smart Scanner will update the existing database instead of creating a completely new one.</p><h3 id="smart-scanner-copy-your-database" tabindex="-1">Copy Your Database <a class="header-anchor" href="#smart-scanner-copy-your-database" aria-label="Permalink to “Copy Your Database”">​</a></h3><figure><img src="/assets/6.B9OcNNfQ.png" alt="Smart Scanner"></figure><p>Copy the generated <strong>database</strong> folder into your MiSTer FPGA Smart Launcher installation directory:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>/media/fat/Scripts/MiSTer-Smart-Launcher</span></span></code></pre></div><div class="danger custom-block"><p class="custom-block-title custom-block-title-default">DANGER</p><p>Replace the existing <strong>database</strong> folder with the newly generated one, otherwise Smart Launcher will continue using the previous database.</p></div><h2 id="smart-launcher" tabindex="-1">Smart Launcher <a class="header-anchor" href="#smart-launcher" aria-label="Permalink to “Smart Launcher”">​</a></h2><figure><img src="/assets/1.Kyc2o1_J.png" alt="Smart Launcher"></figure><p><strong>MiSTer FPGA Smart Launcher</strong> is a web application for MiSTer FPGA that lets you browse your game library, search and filter your ROM collection, and launch games from any device with a web browser, including PCs, smartphones, and tablets.</p><p>The application runs a lightweight web server directly on your MiSTer FPGA, so no additional software is required on the client device.</p><h3 id="smart-launcher-before-you-begin" tabindex="-1">Before You Begin <a class="header-anchor" href="#smart-launcher-before-you-begin" aria-label="Permalink to “Before You Begin”">​</a></h3><p>Smart Launcher relies on a <strong>database</strong> that contains information about your ROM collection.</p><p>Before installing Smart Launcher, you must generate this database using <strong>MiSTer FPGA Smart Scanner</strong>.</p><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>If you haven&#39;t created the database yet, follow the <strong>Smart Scanner</strong> guide before continuing with this installation.</p></div><h3 id="smart-launcher-installation" tabindex="-1">Installation <a class="header-anchor" href="#smart-launcher-installation" aria-label="Permalink to “Installation”">​</a></h3><p>After generating the database, follow these steps:</p><ol><li><p>Copy the <strong>MiSTer-Smart-Launcher</strong> folder to:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>/media/fat/Scripts</span></span></code></pre></div></li><li><p>Copy the generated <strong>database</strong> folder into:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>/media/fat/Scripts/MiSTer-Smart-Launcher</span></span></code></pre></div></li><li><p>On your MiSTer FPGA, open the <strong>Scripts</strong> menu.</p></li><li><p>Enter the <strong>MiSTer-Smart-Launcher</strong> folder and launch the <strong>run.sh</strong> script.</p></li></ol><p>Once the application is running, open the following address from any web browser on your local network:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>http://&lt;YOUR-MISTER-IP&gt;:8282</span></span></code></pre></div><p>For example:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>http://192.168.3.10:8282</span></span></code></pre></div><hr><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Smart Launcher is <strong>not</strong> started automatically.</p><p>If you reboot or power off your MiSTer FPGA, you will need to run <strong>run.sh</strong> again. Automatic startup will be available in a future release, allowing Smart Launcher to run automatically whenever your MiSTer FPGA boots.</p></div><h3 id="smart-launcher-launch-game" tabindex="-1">Launch a Game <a class="header-anchor" href="#smart-launcher-launch-game" aria-label="Permalink to “Launch a Game”">​</a></h3><p>Just search your desired game, click on it and then click on Play!</p>`,81)]])}var s=t(a,[[`render`,o]]);export{i as __pageData,s as default};